1	const PROCESSING_FEE = 5;
2	
3	const BASE_PREMIUM: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	  potion: 40,
8	  rune: 25,
9	};
10	
11	type Item = { type: string };
12	type Step = { op: "quote"; items: Item[] };
13	type Scenario = { customer: unknown; steps: Step[] };
14	
15	const itemBasePremium = (item: Item): number => BASE_PREMIUM[item.type] ?? 0;
16	
17	const RUNE_BLOCK_OF_THREE = 60;
18	
19	const sumItemPremiums = (items: Item[]): number => {
20	  const runeCount = items.filter((i) => i.type === "rune").length;
21	  if (runeCount === 3) return RUNE_BLOCK_OF_THREE;
22	  return items.reduce((sum, item) => sum + itemBasePremium(item), 0);
23	};
24	
25	const quote = (step: Step): { premium: number } => ({
26	  premium: sumItemPremiums(step.items) + PROCESSING_FEE,
27	});
28	
29	export const runScenario = (input: unknown): unknown => {
30	  const scenario = input as Scenario;
31	  return { results: scenario.steps.map(quote) };
32	};
